//$Id$
//svg-datalabels-connector.js
import { LabelRegistry } from './label-registry';
import { getLabelHolder } from './datalabelsUtils';
import { appendEle } from '../utils/zcsvgutils';
import { NONE, NULL } from '../core/zc-constants';
import { getRawColor } from '../utils/colorutils';
import { isFacet } from '../axis/hierarchy-axis-utils';
import { pick } from '../utils/zcutils';
import { setOpacityForTickFilterElements } from '../plot/svg/set-pivot-attr';

function connector(chartObj, series, i, rendererIdx, wrap) {
    rendererIdx = pick(rendererIdx, i);

    var properties = (series && series.properties) || {},
        { dataUpdate = [], isSunburst, connectorPath, showlabel, dataLabels = {} } = properties,
        lineConf = dataLabels.line,
        data_length = dataUpdate.length;

    var labelHolder = getLabelHolder(chartObj),
        linkseries = appendEle(
            wrap || labelHolder,
            'g',
            !series || (!isFacet(chartObj) && showlabel === 'circular') ? [] : [1],
            '.',
            'class',
            `link_${rendererIdx}`
        );

    if (!series) {
        return;
    }

    if (!lineConf) {
        return;
    }

    let actualData = properties.data;
    linkseries.attr('transform', properties.translation).styles({
        stroke: lineConf.strokeColor,
        'stroke-width': lineConf.strokeWidth,
        fill: NONE
    });

    series.forEach(function(subSeries, j) {
        let enabled = (subSeries.showlabel || showlabel) !== 'circular';
        var subseries = appendEle(linkseries, 'g', enabled ? [1] : [], '.', 'class', `subseries_${j}`);
        var labelText = appendEle(subseries, 'path', subSeries.dataUpdate || dataUpdate);

        subseries.attr('transform', subSeries.translation);
        labelText
            .styles({
                display: function(d, k) {
                    return subSeries[k].display === false ? NONE : NULL;
                },
                stroke: function(d, k) {
                    if (isSunburst || lineConf.strokeColor) {
                        return NULL;
                    }
                    return getRawColor(chartObj, properties.reverseColor ? data_length - 1 - k : k, d && d.data ? d.data : d, i);
                }
            })
            .attrs({
                d: subSeries.connectorPath || connectorPath,
                class: 'zc_label_connector',
                id: function(d, k) {
                    return `link${i}_${j}_${k}`;
                },
                levelbycolumn: function(_d, i) {
                    let d = actualData ? actualData[actualData.length - 1 - i] : _d.data || _d;
                    if (d.levelByColumn) {
                        return d.levelByColumn;
                    }
                },
                levelbyrow: function(_d, i) {
                    let d = actualData ? actualData[actualData.length - 1 - i] : _d.data || _d;
                    if (d.levelByRow) {
                        return d.levelByRow;
                    }
                }
            });
        setOpacityForTickFilterElements(labelText, chartObj, 'label', actualData);
    });
}

LabelRegistry.add('connector', connector);
export var _svgDatalabelConnector = connector;
